SELECT eiaid_weights.eiaid AS eiaid, resstock_2024_amy2018_release_2_by_state_vu.state AS state, resstock_2024_amy2018_release_2_by_state_vu.timestamp AS timestamp, sum(1) AS sample_count, sum(bs.weight * eiaid_weights.weight) AS units_count, sum(resstock_2024_amy2018_release_2_by_state_vu."out.site_energy.total.energy_consumption" * bs.weight * eiaid_weights.weight) AS "site_energy.total.energy_consumption" FROM resstock_2024_amy2018_release_2_by_state_vu JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = resstock_2024_amy2018_release_2_by_state_vu.bldg_id AND bs.upgrade = 0 AND resstock_2024_amy2018_release_2_by_state_vu.upgrade = 0 AND resstock_2024_amy2018_release_2_by_state_vu.state = 'CO' JOIN eiaid_weights ON bs."in.county" = eiaid_weights.gisjoin WHERE eiaid_weights.eiaid = '4110' GROUP BY 1, 2, 3 ORDER BY 1, 2, 3